   443→void Opencore::StopTheWorld(int pid) {
   444→    char task_dir[32];
   445→    struct dirent *entry;
   446→    snprintf(task_dir, sizeof(task_dir), "/proc/%d/task", pid);
   447→    DIR *dp = opendir(task_dir);
   448→    if (dp) {
