   493→void Opencore::Continue() {
   494→    for (int index = 0; index < threads.size(); index++) {
   495→        ThreadRecord& ts = threads[index];
   496→        if (!ts.attached)
   497→            continue;
   498→
   499→        pid_t tid = ts.pid;
   500→        if (ptrace(PTRACE_DETACH, tid, NULL, 0) < 0)
   501→            continue;
   502→    }
   503→    threads.clear();
   504→}
